patch:
--- a/counter_sync.v
+++ b/counter_sync.v
@@ -1,8 +1,8 @@
 module counter_16bit(
     input clk,
     input rst_n,
     output reg [15:0] count
 );
-    always @(posedge clk)
+    always @(posedge clk or negedge rst_n)
         if (!rst_n)
             count <= 16'h0000;
         else

before_code:
module counter_16bit(
    input clk,
    input rst_n,
    output reg [15:0] count
);
    always @(posedge clk)
        if (!rst_n)
            count <= 16'h0000;
        else
            count <= count + 1'b1;
endmodule

after_code:
module counter_16bit(
    input clk,
    input rst_n,
    output reg [15:0] count
);
    always @(posedge clk or negedge rst_n)
        if (!rst_n)
            count <= 16'h0000;
        else
            count <= count + 1'b1;
endmodule
